10	#include <queue>
11	#include <rime/algo/algebra.h>
12	#include <rime/dict/prism.h>
13	
14	namespace rime {
15	
16	namespace {
17	
18	struct node_t {
19	  string key;
20	  size_t node_pos;
21	};
22	
23	// 在 SpellingDescriptor::type 的高位記錄 is_correction, 避開符號位
24	const int32_t kTypeIsCorrectionMask = 1 << 30;
25	const int32_t kSpellingTypeMask = ~kTypeIsCorrectionMask;
26	
27	}  // namespace
28	
29	const char kPrismFormat[] = "Rime::Prism/4.0";
30	const double kPrismFormatVersion = 4.0;
31	
32	const char kPrismFormatPrefix[] = "Rime::Prism/";
33	const size_t kPrismFormatPrefixLen = sizeof(kPrismFormatPrefix) - 1;
34	
35	const char kDefaultAlphabet[] = "abcdefghijklmnopqrstuvwxyz";
36	
37	SpellingAccessor::SpellingAccessor(prism::SpellingMap* spelling_map,
38	                                   SyllableId spelling_id)
39	    : spelling_id_(spelling_id), iter_(NULL), end_(NULL) {
40	  if (spelling_map &&
41	      spelling_id < static_cast<SyllableId>(spelling_map->size)) {
42	    iter_ = spelling_map->at[spelling_id].begin();
43	    end_ = spelling_map->at[spelling_id].end();
44	  }
45	}
46	
47	bool SpellingAccessor::Next() {
48	  if (exhausted())
49	    return false;
50	  if (!iter_ || ++iter_ >= end_)
51	    spelling_id_ = -1;
52	  return exhausted();
53	}
54	
55	bool SpellingAccessor::exhausted() const {
56	  return spelling_id_ == -1;
57	}
58	
59	SyllableId SpellingAccessor::syllable_id() const {
60	  if (iter_ && iter_ < end_)
61	    return iter_->syllable_id;
62	  else
63	    return spelling_id_;
64	}
65	
66	SpellingProperties SpellingAccessor::properties() const {
67	  SpellingProperties props;
68	  if (iter_ && iter_ < end_) {
69	    int32_t packed_type = iter_->type;
70	    props.type = static_cast<SpellingType>(packed_type & kSpellingTypeMask);
71	    props.is_correction = (packed_type & kTypeIsCorrectionMask) != 0;
72	    props.credibility = iter_->credibility;
73	    if (!iter_->tips.empty())
74	      props.tips = iter_->tips.c_str();
75	  }
76	  return props;
77	}
78	
79	Prism::Prism(const path& file_path)
80	    : MappedFile(file_path), trie_(new Darts::DoubleArray) {}
81	
82	bool Prism::Load() {
83	  LOG(INFO) << "loading prism file: " << file_path();
84	
85	  if (IsOpen())
86	    Close();
87	
88	  if (!OpenReadOnly()) {
89	    LOG(ERROR) << "error opening prism file '" << file_path() << "'.";
90	    return false;
91	  }
92	
93	  metadata_ = Find<prism::Metadata>(0);
94	  if (!metadata_) {
95	    LOG(ERROR) << "metadata not found.";
96	    Close();
97	    return false;
98	  }
99	  if (strncmp(metadata_->format, kPrismFormatPrefix, kPrismFormatPrefixLen)) {
100	    LOG(ERROR) << "invalid metadata.";
101	    Close();
102	    return false;
103	  }
104	  format_ = atof(&metadata_->format[kPrismFormatPrefixLen]);
105	
106	  // 版本檢查: 強制重構舊版本
107	  if (format_ < kPrismFormatVersion - DBL_EPSILON) {
108	    LOG(INFO) << "prism format " << format_ << " is too old. upgrading to "
109	              << kPrismFormatVersion;
110	    Close();
111	    return false;
112	  }
113	
114	  char* array = metadata_->double_array.get();
115	  if (!array) {
116	    LOG(ERROR) << "double array image not found.";
117	    Close();
118	    return false;
119	  }
120	  size_t array_size = metadata_->double_array_size;
121	  LOG(INFO) << "found double array image of size " << array_size << ".";
122	  trie_->set_array(array, array_size);
123	
124	  spelling_map_ = NULL;
125	  if (format_ > 1.0 - DBL_EPSILON) {
126	    spelling_map_ = metadata_->spelling_map.get();
127	  }
128	  return true;
129	}
130	
131	bool Prism::Save() {
132	  LOG(INFO) << "saving prism file: " << file_path();
133	  if (!trie_->total_size()) {
134	    LOG(ERROR) << "the trie has not been constructed!";
135	    return false;
136	  }
137	  return ShrinkToFit();
138	}
139	bool Prism::Build(const Syllabary& syllabary,
140	                  const Script* script,
141	                  uint32_t dict_file_checksum,
142	                  uint32_t schema_file_checksum) {
143	  // building double-array trie
144	  size_t num_syllables = syllabary.size();
145	  size_t num_spellings = script ? script->size() : syllabary.size();
146	  vector<const char*> keys(num_spellings);
147	  size_t key_id = 0;
148	  size_t map_size = 0;
149	  if (script) {
150	    for (auto it = script->begin(); it != script->end(); ++it, ++key_id) {
151	      keys[key_id] = it->first.c_str();
152	      map_size += it->second.size();
153	    }
154	  } else {
155	    for (auto it = syllabary.begin(); it != syllabary.end(); ++it, ++key_id) {
156	      keys[key_id] = it->c_str();
157	    }
158	  }
159	  if (0 != trie_->build(num_spellings, &keys[0])) {
160	    LOG(ERROR) << "Error building double-array trie.";
161	    return false;
162	  }
163	  // creating prism file
164	  size_t array_size = trie_->size();
165	  size_t image_size = trie_->total_size();
166	  const size_t kDescriptorExtraSize = 12;
167	  size_t estimated_map_size =
168	      num_spellings * 12 +
169	      map_size * (4 + sizeof(prism::SpellingDescriptor) + kDescriptorExtraSize);
170	  const size_t kReservedSize = 1024;
171	  if (!Create(image_size + estimated_map_size + kReservedSize)) {
172	    LOG(ERROR) << "Error creating prism file '" << file_path() << "'.";
173	    return false;
174	  }
175	  // creating metadata
176	  auto metadata = Allocate<prism::Metadata>();
177	  if (!metadata) {
178	    LOG(ERROR) << "Error creating metadata in file '" << file_path() << "'.";
179	    return false;
180	  }
181	  metadata->dict_file_checksum = dict_file_checksum;
182	  metadata->schema_file_checksum = schema_file_checksum;
183	  metadata->num_syllables = num_syllables;
184	  metadata->num_spellings = num_spellings;
185	  metadata_ = metadata;
186	  // alphabet
187	  {
188	    set<char> alphabet;
189	    for (size_t i = 0; i < num_spellings; ++i)
190	      for (const char* p = keys[i]; *p; ++p)
191	        alphabet.insert(*p);
192	    char* p = metadata->alphabet;
193	    set<char>::const_iterator c = alphabet.begin();
194	    for (; c != alphabet.end(); ++p, ++c)
195	      *p = *c;
196	    *p = '\0';
197	  }
198	  // saving double-array image
199	  char* array = Allocate<char>(image_size);
200	  if (!array) {
201	    LOG(ERROR) << "Error creating double-array image.";
202	    return false;
203	  }
204	  std::memcpy(array, trie_->array(), image_size);
205	  metadata->double_array = array;
206	  metadata->double_array_size = array_size;
207	  // building spelling map
208	  if (script) {
209	    map<string, SyllableId> syllable_to_id;
210	    SyllableId syll_id = 0;
211	    for (auto it = syllabary.begin(); it != syllabary.end(); ++it) {
212	      syllable_to_id[*it] = syll_id++;
213	    }
214	    auto spelling_map = CreateArray<prism::SpellingMapItem>(num_spellings);
215	    if (!spelling_map) {
216	      LOG(ERROR) << "Error creating spelling map.";
217	      return false;
218	    }
219	    auto i = script->begin();
220	    auto item = spelling_map->begin();
221	    for (; i != script->end(); ++i, ++item) {
222	      size_t list_size = i->second.size();
223	      item->size = list_size;
224	      item->at = Allocate<prism::SpellingDescriptor>(list_size);
225	      if (!item->at) {
226	        LOG(ERROR) << "Error creating spelling descriptors.";
227	        return false;
228	      }
229	      auto j = i->second.begin();
230	      auto desc = item->begin();
231	      for (; j != i->second.end(); ++j, ++desc) {
232	        desc->syllable_id = syllable_to_id[j->str];
233	        // 打包寫入 type + is_correction
234	        int32_t packed_type = static_cast<int32_t>(j->properties.type);
235	        if (j->properties.is_correction) {
236	          packed_type |= kTypeIsCorrectionMask;
237	        }
238	        desc->type = packed_type;
239	        desc->credibility = j->properties.credibility;
240	        if (!j->properties.tips.empty() &&
241	            !CopyString(j->properties.tips, &desc->tips)) {
242	          LOG(ERROR) << "Error creating spelling properties.";
243	          return false;
244	        }
245	      }
246	    }
247	    metadata->spelling_map = spelling_map;
248	    spelling_map_ = spelling_map;
249	  }
250	  // at last, complete the metadata
251	  std::strncpy(metadata->format, kPrismFormat,
252	               prism::Metadata::kFormatMaxLength);
253	  return true;
254	}
255	
256	bool Prism::HasKey(const string& key) {
257	  int value = trie_->exactMatchSearch<int>(key.c_str());
258	  return value != -1;
259	}
260	
261	bool Prism::GetValue(const string& key, int* value) const {
262	  int result = trie_->exactMatchSearch<int>(key.c_str());
263	  if (result == -1) {
264	    return false;
265	  }
266	  *value = result;
267	  return true;
268	}
269	
270	// Given a key, search all the keys in the tree that share
271	// a common prefix with that key.
272	void Prism::CommonPrefixSearch(const string& key, vector<Match>* result) {
273	  if (!result || key.empty())
274	    return;
275	  size_t len = key.length();
276	  result->resize(len);
277	  size_t num_results =
278	      trie_->commonPrefixSearch(key.c_str(), &result->front(), len, len);
279	  result->resize(num_results);
280	}
281	
282	void Prism::ExpandSearch(const string& key,
283	                         vector<Match>* result,
284	                         size_t limit) {
285	  if (!result)
286	    return;
287	  result->clear();
288	  size_t count = 0;
289	  size_t node_pos = 0;
290	  size_t key_pos = 0;
291	  int ret = trie_->traverse(key.c_str(), node_pos, key_pos);
292	  // key is not a valid path
293	  if (ret == -2)
294	    return;
295	  if (ret != -1) {
296	    result->push_back(Match{ret, key_pos});
297	    if (limit && ++count >= limit)
298	      return;
299	  }
300	  std::queue<node_t> q;
301	  q.push({key, node_pos});
302	  while (!q.empty()) {
303	    node_t node = q.front();
304	    q.pop();
305	    const char* c =
306	        (format_ > 1.0 - DBL_EPSILON) ? metadata_->alphabet : kDefaultAlphabet;
307	    for (; *c; ++c) {
308	      string k = node.key + *c;
309	      size_t k_pos = node.key.length();
310	      size_t n_pos = node.node_pos;
311	      ret = trie_->traverse(k.c_str(), n_pos, k_pos);
312	      if (ret <= -2) {
313	        // ignore
314	      } else if (ret == -1) {
315	        q.push({k, n_pos});
316	      } else {
317	        q.push({k, n_pos});
318	        result->push_back(Match{ret, k_pos});
319	        if (limit && ++count >= limit)
320	          return;
321	      }
322	    }
323	  }
324	}
325	
326	SpellingAccessor Prism::QuerySpelling(SyllableId spelling_id) {
327	  return SpellingAccessor(spelling_map_, spelling_id);
328	}
329	
330	size_t Prism::array_size() const {
331	  return trie_->size();
332	}
333	
334	uint32_t Prism::dict_file_checksum() const {
335	  return metadata_ ? metadata_->dict_file_checksum : 0;
336	}
337	
338	uint32_t Prism::schema_file_checksum() const {
339	  return metadata_ ? metadata_->schema_file_checksum : 0;
340	}
341	
342	}  // namespace rime
